def is_private_ip(ip):
    try:
        ip_parts = list(map(int, ip.split('.')))
        if len(ip_parts) != 4:
            return True
        # 127.0.0.0/8
        if ip_parts[0] == 127:
            return True
        # 10.0.0.0/8
        if ip_parts[0] == 10:
