@app.route("/full_ssrf")
def full_ssrf():
    subdomain = request.args.get('subdomain', '')
    if not subdomain:
        return 'Missing subdomain', 400

    # Validate subdomain: alphanumeric and hyphens only, no spaces or special chars
    if not re.match(r'^[a-zA-Z0-9-]+$', subdomain):
        return 'Invalid subdomain', 400

    # Limit length to prevent overflow or absurd names
    if len(subdomain) > 63:
